int cleanup_expired_sessions(SessionCache *cache) {
    if (!cache) {
        return -1;
    }
    
    time_t now = time(NULL);
    int cleaned = 0;
    
    for (size_t i = 0; i < cache->capacity; i++) {
        Session *session = &cache->sessions[i];
        
        if (!session->in_use) {
            continue;
        }
        
        if (session->state == SESSION_ACTIVE && now > session->expires_at) {
            if (session->data) {
                memset(session->data, 0, session->data_len);
                free(session->data);
                session->data = NULL;
                session->data_len = 0;
            }
            session->state = SESSION_EXPIRED;
            cleaned++;
        }
    }
    
    return cleaned;
}

void destroy_session_cache(SessionCache *cache) {
    if (!cache) {
        return;
    }
    
    if (cache->sessions) {
        for (size_t i = 0; i < cache->capacity; i++) {
            if (cache->sessions[i].data) {
                memset(cache->sessions[i].data, 0, cache->sessions[i].data_len);
                free(cache->sessions[i].data);
                cache->sessions[i].data = NULL;
            }
        }
        free(cache->sessions);
    }
    
    free(cache);
}

